export const lpic2_quiz_pool = [
  // Topic 200: Capacity Planning
  { id: 'lpic2-200-1', topicId: 1, question: 'Quelle commande fournit une vue dynamique et en temps réel du système et des processus en cours d\'exécution, en mettant en évidence l\'utilisation du processeur et de la mémoire ?', options: ['free', 'top', 'uptime', 'vmstat'], answer: 1, explanation: 'La commande `top` offre une vue en temps réel de l\'activité du système.' },
  { id: 'lpic2-200-2', topicId: 1, question: 'Laquelle des commandes suivantes utiliseriez-vous pour voir des statistiques détaillées d\'E/S pour les périphériques de blocs ?', options: ['vmstat', 'iostat', 'netstat', 'mpstat'], answer: 1, explanation: 'La commande `iostat` est utilisée pour surveiller la charge des périphériques d\'entrée/sortie.' },
  { id: 'lpic2-200-3', topicId: 1, question: 'Vous souhaitez collecter et visualiser les tendances de performances du système sur plusieurs mois. Quel outil est le plus approprié ?', options: ['top', 'ss', 'Collectd/MRTG/Cacti', 'tcpdump'], answer: 2, explanation: 'Collectd, MRTG et Cacti sont des outils standard conçus pour collecter des données au fil du temps et générer des graphiques pour la planification des capacités.' },
  { id: 'lpic2-200-4', topicId: 1, question: 'Quel outil pouvez-vous utiliser pour prévoir les besoins futurs en capacité en fonction des tendances de trafic ?', options: ['mrtg', 'ping', 'fsck', 'ls'], answer: 0, explanation: 'MRTG (Multi Router Traffic Grapher) est utilisé pour surveiller le trafic et la capacité au fil du temps.' },
  { id: 'lpic2-200-5', topicId: 1, question: 'À quoi sert la commande `sar` ?', options: ['Chercher des fichiers', 'System Activity Reporter (Informe sur l\'activité du système)', 'Sauvegarder des archives', 'Arrêter tous les processus'], answer: 1, explanation: '`sar` fait partie de sysstat et sert à collecter, rapporter et sauvegarder l\'activité du système.' },

  // Topic 201: Linux Kernel
  { id: 'lpic2-201-1', topicId: 2, question: 'Où résident par défaut les modules du noyau (kernel modules) compilés ?', options: ['/boot/modules/', '/lib/modules/$(uname -r)/', '/etc/kernel/', '/var/lib/modules/'], answer: 1, explanation: 'Les modules du noyau se trouvent dans `/lib/modules/` sous un dossier correspondant à la version spécifique du noyau.' },
  { id: 'lpic2-201-2', topicId: 2, question: 'Quel type cible (target) `make` est utilisé pour construire une image de noyau compressée moderne ?', options: ['make zImage', 'make bzImage', 'make vmlinux', 'make install'], answer: 1, explanation: '`make bzImage` crée une image du noyau compressée (big zImage) contournant les limitations d\'architecture de l\'ancienne zImage.' },
  { id: 'lpic2-201-3', topicId: 2, question: 'Lors de la compilation du noyau à partir des sources, quelle commande fournit une interface textuelle avec des menus ?', options: ['make config', 'make menuconfig', 'make xconfig', 'make defconfig'], answer: 1, explanation: '`make menuconfig` requiert ncurses et offre une interface en mode console.' },
  { id: 'lpic2-201-4', topicId: 2, question: 'Quel outil est utilisé pour charger intelligemment un module du noyau avec toutes ses dépendances ?', options: ['insmod', 'modinfo', 'modprobe', 'rmmod'], answer: 2, explanation: '`modprobe` ajoute ou supprime des modules du noyau et résout automatiquement leurs dépendances.' },
  { id: 'lpic2-201-5', topicId: 2, question: 'Quel fichier sert de table des symboles du noyau, cartographiant les adresses mémoires nécessaires pour le débogage ?', options: ['vmlinux', 'System.map', 'bzImage', 'initrd'], answer: 1, explanation: 'Le fichier `System.map` contient les adresses en mémoire des fonctions (symboles) du noyau.' },

  // Topic 202: System Startup
  { id: 'lpic2-202-1', topicId: 3, question: 'Sous l\'ancien système SysVinit, quel fichier dicte le niveau d\'exécution (runlevel) par défaut au démarrage ?', options: ['/etc/inittab', '/etc/runlevel', '/boot/grub/grub.cfg', '/etc/init.d/rcS'], answer: 0, explanation: 'Le ficher `/etc/inittab` définit le runlevel initdefault.' },
  { id: 'lpic2-202-2', topicId: 3, question: 'Quelle commande met à jour le fichier de configuration GRUB 2 sur les systèmes basés sur Debian/Ubuntu ?', options: ['grub-install', 'grub2-mkconfig', 'update-grub', 'grub-setup'], answer: 2, explanation: '`update-grub` est le script Debian qui exécute en arrière-plan `grub-mkconfig`.' },
  { id: 'lpic2-202-3', topicId: 3, question: 'Pendant une récupération, vous devez démarrer en mode "mono-utilisateur" sous systemd. Quelle cible (target) est utilisée ?', options: ['runlevel1.target', 'rescue.target', 'single.target', 'emergency.target'], answer: 1, explanation: 'La cible `rescue.target` est l\'équivalent systemd du single-user mode de SysVinit.' },
  { id: 'lpic2-202-4', topicId: 3, question: 'Où est généralement stocké le fichier de configuration final généré pour GRUB 2 ?', options: ['/boot/grub/grub.conf', '/boot/grub2/grub2.cfg', '/boot/grub/grub.cfg', '/etc/grub.cfg'], answer: 2, explanation: 'Le fichier principal GRUB 2 est généré dans `/boot/grub/grub.cfg` (ou grub2/ selon la distro).' },
  { id: 'lpic2-202-5', topicId: 3, question: 'Quel paramètre ajoutez-vous à la ligne de commande du noyau via GRUB pour contourner systemd/init et obtenir un terminal root ?', options: ['init=/bin/sh', 'single', 'rescue', 'bash'], answer: 0, explanation: 'Ajouter `init=/bin/sh` demande au noyau de lancer directement le shell plutôt que le démon d\'initialisation classique.' },

  // Topic 203: Filesystem and Devices
  { id: 'lpic2-203-1', topicId: 4, question: 'Quel système de fichiers centré sur les "extents" est devenu la valeur par défaut pour la famille RHEL (Red Hat 7+) ?', options: ['ext4', 'xfs', 'btrfs', 'zfs'], answer: 1, explanation: 'XFS est très évolutif en E/S et a été choisi par Red Hat comme système de fichiers par défaut.' },
  { id: 'lpic2-203-2', topicId: 4, question: 'Quelle commande vérifie un système de fichiers ext4 à la recherche d\'erreurs ?', options: ['fsck.ext4', 'e2fsck', 'Les deux (A et B)', 'xfs_repair'], answer: 2, explanation: '`fsck.ext4` est souvent un lien symbolique ou un wrapper pointant vers `e2fsck`.' },
  { id: 'lpic2-203-3', topicId: 4, question: 'Quel est l\'objectif du fichier `/etc/fstab` ?', options: ['Configurer les interfaces réseau', 'Détailler les systèmes de fichiers statiques à monter au démarrage', 'Stocker les mots de passe', 'Gérer le secteur d\'amorçage'], answer: 1, explanation: 'fstab (file systems table) indique au système comment monter et configurer les partitions disques.' },
  { id: 'lpic2-203-4', topicId: 4, question: 'Dans smartctl, quelle option fournit une vérification d\'état de santé S.M.A.R.T. rapide (PASSED/FAILED) ?', options: ['-a', '-H', '-i', '-t short'], answer: 1, explanation: 'Le paramètre `-H` génère une recommandation globale sur la santé du disque.' },
  { id: 'lpic2-203-5', topicId: 4, question: 'Comment cloner le contenu entier d\'un CD-ROM vers un fichier image ISO byte par byte ?', options: ['tar -cvf image.iso /dev/cdrom', 'dd if=/dev/cdrom of=image.iso', 'mkisofs -o image.iso /dev/cdrom', 'cp /dev/cdrom image.iso'], answer: 1, explanation: '`dd` effectue une copie de bas niveau de flux de blocs de "input file" vers "output file".' },

  // LVM, RAID, Network, Backup... (Translated subset to French)
  // Topic 204: Advanced Storage
  { id: 'lpic2-204-1', topicId: 5, question: 'Quel outil est utilisé pour gérer et surveiller un array RAID logiciel (Software RAID) sous Linux ?', options: ['lvm', 'fdisk', 'mdadm', 'parted'], answer: 2, explanation: '`mdadm` (Multiple Device Admin) est l\'outil principal pour le RAID logiciel Linux.' },
  { id: 'lpic2-204-2', topicId: 5, question: 'Quel niveau de RAID permet d\'appliquer la mise en miroir parfaite (data mirroring) sans agrégation par bandes (striping) ?', options: ['RAID 0', 'RAID 1', 'RAID 5', 'RAID 10'], answer: 1, explanation: 'Le RAID 1 réplique les données exactes sur plusieurs disques (miroir).' },
  { id: 'lpic2-204-3', topicId: 5, question: 'En LVM, quelle commande allonge un Groupe de Volumes (Volume Group) existant en y ajoutant un nouveau disque physique initialisé ?', options: ['pvcreate', 'vgextend', 'lvextend', 'vgcreate'], answer: 1, explanation: '`vgextend` (Volume Group Extend) incorpore un Physical Volume au VG.' },
  { id: 'lpic2-204-4', topicId: 5, question: 'Quel paramètre utilise `hdparm` pour évaluer les performances de lecture brutes sans cache mémoire tampon ?', options: ['-T', '-S', '-t', '-y'], answer: 2, explanation: 'Le paramètre `-t` exécute des tests chronométrés de lecture du périphérique ("timing buffered disk reads").' },
  { id: 'lpic2-204-5', topicId: 5, question: 'À quoi sert principalement iSCSI ?', options: ['Pare-feu Web', 'Encapsuler les protocoles de commandes SCSI sur un réseau IP TCP standard', 'Déchiffrer des mots de passe', 'Outil Cacti d\'audit logiciel.'], answer: 1, explanation: 'iSCSI transmet des commandes de blocs de stockage SCSI au travers de réseaux TCP/IP (SANs).' },

  // Topic 205: Network Configuration
  { id: 'lpic2-205-1', topicId: 6, question: 'Quelle commande moderne du paquet `iproute2` permet de lire le cache de la table ARP (voisins) ?', options: ['arp -n', 'ip neigh show', 'netstat -rn', 'route -n'], answer: 1, explanation: '`ip neigh show` remplace la commande arp classique.' },
  { id: 'lpic2-205-2', topicId: 6, question: 'Pour afficher les tables de routage, quelle est la commande de la suite iproute2 ?', options: ['route', 'ip route show', 'netstat -r', 'ifconfig'], answer: 1, explanation: 'La commande `ip route show` gère le routage réseau.' },
  { id: 'lpic2-205-3', topicId: 6, question: 'Quel est l\'impact de l\'option `-c 4` sur la commande `ping` ?', options: ['Tester 4 hôtes différents', 'Envoyer seulement quatre requêtes d\'écho (echo_request) puis s\'arrêter', 'Pinger le port 4', 'Vérifier l\'IPv6'], answer: 1, explanation: 'L\'option `-c` détermine le C-ount limite.' },
  { id: 'lpic2-205-4', topicId: 6, question: 'Quel outil en ligne de commande sert conventionnellement d\'analyseur/sniffer de trafic de paquets réseau ?', options: ['wireshark', 'nmap', 'tcpdump', 'tracepath'], answer: 2, explanation: 'Le classique `tcpdump` est un utilitaire renifleur (sniffer) exécuté dans un terminal.' },
  { id: 'lpic2-205-5', topicId: 6, question: 'Sur quel port TCP le trafic Web chiffré HTTPS est-il couramment conduit ?', options: ['80', '21', '22', '443'], answer: 3, explanation: 'Le port assigné HTTPS(SSL/TLS) est 443.' },

  // Topic 206: System Maintenance
  { id: 'lpic2-206-1', topicId: 7, question: 'Lors de la compilation locale d\'une archive source tarball (.tar.gz) en logiciel C, quel en est l\'ordre usuel ?', options: ['make > make install > ./configure', './configure > make > make install', 'make install > ./configure > make', 'untar > make install > ./configure'], answer: 1, explanation: 'Généralement, on exécute: `./configure` pour créer les Makefiles, puis `make` pour la compilation et `make install` pour déployer.' },
  { id: 'lpic2-206-2', topicId: 7, question: 'Quel utilitaire synchronise les fichiers de manière extrêmement rapide à travers des connexions en calculant les deltas et différences au lieu de renvoyer le document entier ?', options: ['cp', 'scp', 'ftp', 'rsync'], answer: 3, explanation: 'L\'outil rsync emploie des algorithmes différentiels intelligents évitant le transfert intégral.' },
  { id: 'lpic2-206-3', topicId: 7, question: 'Que trace le programme `strace` ?', options: ['Tester des vulnérabilités de port web', 'Tracer les appels système (system calls) et les signaux interfacés par le noyau aux applications', 'Scanner le système de fichier', 'Lire des variables d\'environnement'], answer: 1, explanation: '`strace` est un utilitaire de diagnostic crucial pour surveiller les System Calls émis par un PID.' },
  { id: 'lpic2-206-4', topicId: 7, question: 'Quelle commande établit l\'inventaire précis de tous les descripteurs de fichiers actuellement ouverts et retenus par le système (en n\'oubliant pas les sockets ou ports) ?', options: ['lsof', 'ps', 'top', 'find'], answer: 0, explanation: '`lsof` se traduit par List Open Files, très utile pour identifier les processus bloquants sur un volume.' },
  { id: 'lpic2-206-5', topicId: 7, question: 'Avec quels indicateurs (flags) la commande GNU `tar` dépiaute-t-elle l\'archivage traditionnel de type tar.gz?', options: ['-cvf', '-xvf', '-zxvf', '-jcvf'], answer: 2, explanation: 'Le raccourci -z signifie désarchiver gzip, -x précise l\'eXtract, -v Verbose Logging, -f pour identifier le Fichier.' },

  // Topic 207-212: Subset Translation
  { id: 'lpic2-207-1', topicId: 8, question: 'Dans l\'univers BIND (DNS), quel type de champ (record) cartographie exclusivement un nom d\'hôte FQDN avec une adresse numérique de format IPv4 ?', options: ['MX', 'CNAME', 'A', 'AAAA'], answer: 2, explanation: 'L\'enregistrement Type A (Address).' },
  { id: 'lpic2-207-2', topicId: 8, question: 'Laquelle des méthodes teste le parsing syntaxique et les variables macros d\'une infrastructure domaine avant de recharger la Zone ?', options: ['named-checkconf', 'named-checkzone', 'dns-lint', 'dig'], answer: 1, explanation: 'La commande `named-checkzone` confirme que la Zone BIND est formellement exempte d\'erreurs bloquantes.' },
  { id: 'lpic2-207-3', topicId: 8, question: 'Quelle est la spécialité d\'un attribut DNS appelé MX Record ?', options: ['Traductions Inverse IP', 'Résoudre quel relais serveur (Mail Exchange) obtiendra localement les flux d\'e-mail adressés ce nom de domaine.', 'Lier l\'intranet LDAP.', 'Mettra jour DDNS.'], answer: 1, explanation: 'Il désigne les hôtes Mails ou les MTA qui acheminent le courrier entrant.' },
  { id: 'lpic2-207-4', topicId: 8, question: 'Quel acronyme illustre l\'ajout essentiel de signatures asymétriques destinées à endiguer les attaques d\'empoisonnement DNS (cache poisoning/spoofing) ?', options: ['DNS-Over-HTTPS (DoH)', 'TLS', 'DNSSEC', 'TSIG'], answer: 2, explanation: 'Le protocole DNSSEC fournit une vérification cryptographique des réponses renvoyées par les DNS.' },
  { id: 'lpic2-207-5', topicId: 8, question: 'Où le démon BIND s\'attend-il à piocher sa configuration principale sur la plupart des partitions UNIX ?', options: ['/etc/bind/bind.conf', '/etc/named.conf', '/var/named/config', '/etc/resolv.conf'], answer: 1, explanation: 'Conventionnellement, c\'est dans le fichier global `/etc/named.conf`.' },

  { id: 'lpic2-208-1', topicId: 9, question: 'Dans la config httpd (Apache Server), quelle directive encadre et rend faisable l\'hébergement de plusieurs sites ou sous-domaines cohabitant sur un serveur unique port TCP ?', options: ['<Directory>', '<ServerHost>', '<VirtualHost>', '<Website>'], answer: 2, explanation: 'La syntaxe de bloc `<VirtualHost>` crée des conteneurs pour abriter les configurations mutuelles.' },
  { id: 'lpic2-208-2', topicId: 9, question: 'Pour quelle fonction particulière le moteur Nginx Server prédomine-t\'il souvent la scène des DevOps par rapport aux origines ?', options: ['Son rôle autenthificateur LDAP', 'Une ingéniérie hautement résiliente (Event-Based) exploitée comme Serveurs proxy inverses et Répartiteurs de Charge efficaces.', 'C\'est l\'implémentation IPv6 OpenVPN.', 'Moteur de base de données Graphique'], answer: 1, explanation: 'Nginx excelle naturellement en tant que front ISP (Reverse-Proxy, Load-Balancer) dû à son mécanisme asynchrone non-bloquant.' },
  { id: 'lpic2-208-3', topicId: 9, question: 'En entreprise, le daemon "Squid" se justifie la plupart du temps comme étant :', options: ['Un relai applicatif LDAP.', 'Un moteur Cache Proxy Web de haute performance optimisant la bande passante et filtrant les hôtes.', 'Hyperviseur Virtualisation', 'Script de Boot Manager.'], answer: 1, explanation: 'Il mémorise les requêtes Internet (HTTP, HTTPS caching proxy) et permet l\'édification de solides règles listes ACL d\'accès pour le LAN.' },
  { id: 'lpic2-208-4', topicId: 9, question: 'Dans Apache HTTPD, quel Modulaire natif intervient pour crypter et assouplir la manipulation des clés TLS, donnant lieu à la protection HTTPS sur le Port 443 ?', options: ['mod_rewrite', 'mod_security', 'mod_ssl', 'mod_proxy'], answer: 2, explanation: '`mod_ssl` intègre rigoureusement SSL/TLS via la liaison au bibliothèques libssl.' },
  { id: 'lpic2-208-5', topicId: 9, question: 'Le cache proxy Squid ouvre une écoute par défaut sur quel port TCP spécifique lors de sa mise en service sans personnalisation ?', options: ['80', '443', '3128', '8080'], answer: 2, explanation: 'Par défaut, Squid intercepte les requêtes web passantes via le connecteur assigné TCP sur le socket 3128.' },

  { id: 'lpic2-209-1', topicId: 10, question: 'Lequel de ces programmes natifs émule spécifiquement et magistralement les suites de protocoles Microsoft réseau (NetBIOS et Server Message Block CIFS) au sein de plateformes type Red Hat/Debian ?', options: ['NFS', 'Samba', 'FTP', 'SSHFS'], answer: 1, explanation: 'Samba accomplit le miracle d\'interfacer le mode Client et contrôleur de domaine SMB/CIFS vers/depuis d\'Unix.' },
  { id: 'lpic2-209-2', topicId: 10, question: 'Sur quel chemin s\'édite la configuration fondatrice et générale déterminant le sort comportemental pour le démon de serveur Samba ?', options: ['/etc/smb/smb.conf', '/etc/samba/smb.conf', '/usr/local/samba.cfg', '/var/lib/samba/config'], answer: 1, explanation: 'L\'endroit pivot demeure fermement `/etc/samba/smb.conf`.' },
  { id: 'lpic2-209-3', topicId: 10, question: 'Dans l\'univers propre au Network File System RPC (NFS), où sont textuellement écrites les déclarations des points de montage et la permissivité des IP clientes ?', options: ['/etc/exports', '/etc/nfs.conf', '/etc/fstab', '/etc/samba/smb.conf'], answer: 0, explanation: 'Tout le partage visible du serveur monte depuis le relevé stocké dans `/etc/exports`.' },
  { id: 'lpic2-209-4', topicId: 10, question: 'De quelle syntaxe se dote le System Admin pour forcer l\'application et la prise en compte à chaud des nouvelles modifications établies sur Exports en protocole NFS sans perturber le client rpc lié ?', options: ['nfs-update', 'systemctl reload nfs', 'exportfs -a / -r', 'mount -a'], answer: 2, explanation: 'L\'usage typique `exportfs -r` indique l\'actualisation invisible des Exports dictés.' },
  { id: 'lpic2-209-5', topicId: 10, question: 'Dans la mesure où l\'arborescence login de samba ne recoupe pas purement les mdp de l\'OS /etc/shadow. Quelle utilité invoquerez-vous couramment pour insérer la password Windows / SMB alloué pour votre Linux User préexistant ?', options: ['smbpasswd -a', 'useradd', 'passwd', 'pdbedit -n'], answer: 0, explanation: 'La saisie locale de `smbpasswd -a username` insère formellement la chaîne hachée vers la table interne SAM.' },

  { id: 'lpic2-210-1', topicId: 11, question: 'Afin d\'attribuer à la volée tout un pool d\'adresses réseau IP et DNS à des PC branchés sur un réseau physique dynamique (leases), on privilégie l\'exploitation standard du démon de service nommé :', options: ['DNS', 'DHCP', 'ARP', 'ICMP'], answer: 1, explanation: 'Le protocole DHCP (Dynamic Host Configuration Protocol) donne dynamiquement toute configuration L2-L3 aux postes.' },
  { id: 'lpic2-210-2', topicId: 11, question: 'L\'initiative du framework interne Pluggable Authentication Modules (PAM) sous Linux a remédié fondamentalement à :', options: ['Créer l\'Indépendance absolu de Code et de la compilation pour les Programmes hôtes par rapport aux Moteurs, Bases et règles complexes employées pour Vérifier leur Authentification Identity/Token.', 'Le Pare-feu des Interfaces', 'L\'Initialisation Boot initramfs', 'La mise à disposition centralisée de volumes'], answer: 0, explanation: 'PAM soulage le développement. Au lieu que le processus tel "login" se code lui-même une prise LDAP, il ne fera que questionner l\'Interface PAM modulaire existante sans aucune manipulation de script.' },
  { id: 'lpic2-210-3', topicId: 11, question: 'À propos de LDAP, comment le définit-on architecturalement dans l\'esprit de Network Directory global ?', options: ['Lightweight Directory Access Protocol (Sert principalement d\'annuaire rapide, centralisé et hiérarchique contenant souvent la base de profils IdM et Permissions des comptes).', 'Local Database Administration (Pour DBs SQL)', 'Link Domain Aggregation (Bonding port)', 'Linux DNS Authority'], answer: 0, explanation: 'Ldap reste l\'épine dorsale de requêtes de données et Credentials orientées Objet/Annuaire en Active Directories et OpenLdap.' },
  { id: 'lpic2-210-4', topicId: 11, question: 'Dans le cadre point-à-point d\'un Tunnel Virtuel monté par OpenVPN employant le noeud de bloc de type adaptateur the `TUN` ; sur quelle classe OSI transite virtuellement cette méthode de paquets précis ?', options: ['Switching Pont / Layer 2 MAC Address Ethernet Bridge', 'La Capa 3 IP Routing et datagrams', 'Encapsulation Physique L1', 'Portes de transport L4 UDP exclusivement encapsulées.'], answer: 1, explanation: 'L\'interface TUN virtualise stricto sensu la pile de Couche Réseau (Layer 3 de l\'IP v4/v6) évitant l\'encombrement des adresses datalink du pont TAP.' },
  { id: 'lpic2-210-5', topicId: 11, question: 'Selon les normes validées et non personnalisées, OpenVPN attache en backend local son service Listener vers cette porte protocolaire et ce moyen technique de datagramme :', options: ['1194 UDP', '22 TCP', '443 TCP', '53 UDP'], answer: 0, explanation: 'D\'emblée, l\'affectation native standard prévilégiée est d\'écouter par flux UDP (non-orienté connexion pour éviter un collapse) basé sur le port 1194.' },

  { id: 'lpic2-211-1', topicId: 12, question: 'Par l\'intermédiaire de quel protocole universel en internet les Agents MTA (tel Postfix, Exim) relient-ils le message formaté d\'un ordinateur local à un ordinateur serveur distant dans l\'échange et le Push du courrier ?', options: ['POP3', 'IMAP', 'SMTP', 'SNMP'], answer: 2, explanation: 'SMTP, standard sur les ports 25, 465, et 587, gère et transmet inlassablement en sortant / relaying les blocs Mails des enveloppes TCP.' },
  { id: 'lpic2-211-2', topicId: 12, question: 'Axe de réflexion sur les fichiers config MTA.. Sachant que le paramètre `master.cf` lance les serveurs d\'attente. Où, au sein de Postfix, l\'Admi Système déclare-t-il les Directives Maîtresses concernant les Hostnames gérés, l\'acheminement DNS relay et le paramètre MailDir ?', options: ['/etc/postfix/master.cf', '/etc/postfix/main.cf', '/etc/mail/sendmail.cf', '/var/spool/postfix/config'], answer: 1, explanation: 'Le `main.cf` gouverne d\'ordre majeur toute la flexibilité locale et les filtres (smtpd_restrictions) basés pour MTA.' },
  { id: 'lpic2-211-3', topicId: 12, question: 'Lequel est de nos jours la passerelle (Client-Polling / MDA) IMAP Pop d\'une popularité impérieuse et imperturbable utilisée par la majorité des panel Mails pour servir le trafic d\'application vers Outlook et Mobiles Web ?', options: ['Postfix', 'Dovecot', 'Procmail', 'Squid'], answer: 1, explanation: 'Dovecot Server interprète et propulse depuis des disques Unix vers des protocoles sécurisés comme IMapS et PopS per les interfaces EndUser.' },
  { id: 'lpic2-211-4', topicId: 12, question: 'Si un Sysadmin utilise la commande local MDA "Procmail" ou met à jour des "Sieve Scripts" ; Sa mission correspond probablement à :', options: ['Distribuer dynamiquement un Mail arrivant depuis un Inbox et ordonnancer des conditions logiques telles que déposer les Spams dans Junk et classer les en-têtes.', 'Créer une zone DNSMX.', 'Augmenter le Kernel Module réseau.', 'Cacher des Sites Websites en SQUID.'], answer: 0, explanation: 'Sieve/Procmail excellent à filtrer, parser, relayer, détruire ou ranger localement en dossier précis le mail au moment M où le Postfix termine sa Livraison Local.' },
  { id: 'lpic2-211-5', topicId: 12, question: 'Dans la philosophie de sendmail sur un OS Linux: Vous configurez et attribuez des noms fictifs via `/etc/aliases`. Quel déclencheur compile le format source texte en Database Rapide de Hash Hash (alias.db) attendue par d\'autres composants ?', options: ['makemap', 'newaliases', 'postmap', 'systemctl reload postfix'], answer: 1, explanation: 'Appelé, `newaliases` digère le fichier local .aliases plain-txt et refabrique l\'index.' },

  { id: 'lpic2-212-1', topicId: 13, question: 'Dans la ligne terminale du netfilter noyau historique (iptables), Quelle Tableau interne concentre de par son origine l\'attribution précise des Règles dites d\'altération des plages Addresses, tel que le Port Forward et l\'anonymat sortant masquerade des Sous-réseaux privés ?', options: ['filter', 'mangle', 'nat', 'raw'], answer: 2, explanation: 'Les commandes basées via iptables appelées à restructurer par `SNAT` ainsi que par Destination NAT se glissent dans le composant Table `nat`.' },
  { id: 'lpic2-212-2', topicId: 13, question: 'Le contexte applicatif qui lit astucieusement tous vos Journaux d\'Authentification (/var/log/auth.log) et qui va subitement ordonner une création temporaire de Banishment Fail rule sur Iptable en décelant un bot d\'Attaque Brute-Force en plein processus d\'intrusion s\'appelle :', options: ['Snort / Suricata', 'Fail2ban', 'Nmap', 'OpenVAS/Nessus'], answer: 1, explanation: 'Il compte les rejets via Filtres de RegExp internes, et de manière chirurgicale Fail2Ban isole instantanément l\'adresse IP distante suspecte du serveur.' },
  { id: 'lpic2-212-3', topicId: 13, question: 'En Pen-Testing Audits OSINT de Linux : La méthode permettant d\'agresser et balayer simultanément l\'étendue des services TCP/UDP dissimulés, identifier discrètement les Versions des Systèmes (Fingerprint) à travers un CLI complet serait l\'emploi par :', options: ['tcpdump stream capture', 'wireshark analizer LAN', 'nmap host & versions mapping scanner tool', 'ping sweeping scanner'], answer: 2, explanation: 'PortScanner NMAP exécute the Network Mapping universel pour cibler les vecteurs de services existants vers l\'extérieur.' },
  { id: 'lpic2-212-4', topicId: 13, question: 'Pour s\'inscrire dans des cycles de Sécurité Avancée, le portail Manager `OpenVAS`, qui s\'est distingué du projet fermé Nessus Security... consiste principalement en ?', options: ['Une Suite d\'Audits massive et d\'Assessment des Vulnérabilités informatiques à jour, exécutée au service Scanner C/S depuis la fondation GVM.', 'Outil qui génère Caches Squid.', 'Modèle PAM LDAP client.', 'Interface Web SSL Let\'sEncrypt.'], answer: 0, explanation: 'Dévolu spécifiquement pour le Vulnerability Test et décelant tout manquement sur version obsolete CVE Patch manquant du réseau et du Cloud.' },
  { id: 'lpic2-212-5', topicId: 13, question: 'Par convention formelle Iptables Filter... Quelle indication ligne bash réordonne indéniablement et pour tout trafic IP imprévu, que le destinataire de la chaine INPUT (Si la condition est Default sans rule appropriées) soit effacé, rendu sourd et détruit de base ?', options: ['iptables -A INPUT -j DROP', 'iptables -P INPUT DROP', 'iptables -I INPUT DROP', 'iptables -D INPUT DROP'], answer: 1, explanation: 'L\'Arg `-P` est destiné à fixer inaltérablement le POLICY fondamental pour une Table.' },

  // --- NOUVEAU BATCH 1 (Thèmes 200-204) ---
  { id: 'lpic2-200-6', topicId: 1, question: 'Dans la sortie de `vmstat`, que signifie la colonne `wa` ?', options: ['Attente processeur', 'Attente d\'E/S', 'Attente réseau', 'Attente d\'allocation mémoire'], answer: 1, explanation: 'La colonne `wa` dans `vmstat` indique le pourcentage de temps pendant lequel le processeur était inactif alors que le système avait des requêtes d\'E/S disque en attente.' },
  { id: 'lpic2-200-7', topicId: 1, question: 'Quelle commande fournit un résumé rapide des moyennes de charge du système (load averages) pour les 1, 5 et 15 dernières minutes ?', options: ['w', 'uptime', 'Les deux (A et B)', 'sar'], answer: 2, explanation: 'Les commandes `w` et `uptime` affichent toutes deux les moyennes de charge du système.' },
  { id: 'lpic2-200-8', topicId: 1, question: 'Quel est le protocole principal utilisé par MRTG pour collecter des données auprès des équipements réseau ?', options: ['SSH', 'SMTP', 'SNMP', 'HTTP'], answer: 2, explanation: 'MRTG (Multi Router Traffic Grapher) s\'appuie principalement sur SNMP (Simple Network Management Protocol) pour recueillir des métriques.' },
  { id: 'lpic2-200-9', topicId: 1, question: 'Quelle commande affiche les statistiques des interfaces réseau, y compris les paquets rejetés et les erreurs de dépassement (overrun) ?', options: ['netstat -i', 'netstat -r', 'netstat -tulnp', 'ifconfig -a'], answer: 0, explanation: '`netstat -i` affiche un tableau de toutes les interfaces réseau et leurs statistiques de transmission/réception respectives.' },
  { id: 'lpic2-200-10', topicId: 1, question: 'Quelle valeur de mémoire dans la sortie de la commande `free` est la plus révélatrice de la mémoire disponible pour lancer de nouvelles applications sans swap ?', options: ['total', 'used', 'shared', 'available'], answer: 3, explanation: 'La colonne `available` estime la quantité de mémoire disponible pour démarrer de nouvelles applications sans échange physique (swapping).' },
  { id: 'lpic2-200-11', topicId: 1, question: 'Comment configurer Collectd pour stocker les métriques de manière efficace au fil du temps ?', options: ['Écrire dans des fichiers CSV', 'Écrire via RRDtool', 'Écrire uniquement dans MySQL', 'Écrire dans syslog'], answer: 1, explanation: 'Collectd utilise souvent le plugin RRDtool (Round Robin Database) pour stocker efficacement les données de séries chronologiques.' },
  { id: 'lpic2-200-12', topicId: 1, question: 'Quel outil est spécifiquement conçu pour afficher l\'utilisation des E/S par processus en temps réel, de manière similaire à `top` ?', options: ['iotop', 'iostat', 'ioping', 'blktrace'], answer: 0, explanation: '`iotop` affiche une interface de type top présentant la bande passante de lecture et d\'écriture des E/S par processus.' },
  { id: 'lpic2-200-13', topicId: 1, question: 'Que suggère fortement une valeur `si` et `so` élevée dans `vmstat` ?', options: ['Congestion réseau', 'Goulot d\'étranglement du processeur', 'Pénurie de mémoire et échange (swapping) intense', 'Défaillance matérielle du disque'], answer: 2, explanation: 'Des taux élevés de Swap In (`si`) et Swap Out (`so`) indiquent que le système déplace activement la mémoire vers le disque en raison de l\'épuisement de la RAM.' },
  { id: 'lpic2-200-14', topicId: 1, question: 'Quelle commande liste tous les sockets TCP et UDP à l\'écoute ainsi que le PID du processus ?', options: ['ss -tulnp', 'netstat -rn', 'ip route', 'arp -a'], answer: 0, explanation: '`ss -tulnp` (ou netstat -tulnp) liste les ports d\'écoute TCP/UDP et les identifiants de processus (PID) associés.' },
  { id: 'lpic2-200-15', topicId: 1, question: 'Dans la planification des capacités, qu\'est-ce qu\'une "ligne de base" (baseline) ?', options: ['La capacité maximale du serveur', 'La RAM minimale requise pour démarrer', 'Des données historiques représentant le comportement normal du système', 'La limite physique de la carte réseau'], answer: 2, explanation: 'Une ligne de base est un état connu et normal du système enregistré au fil du temps pour servir de comparaison face aux anomalies ou à la croissance future.' },

  { id: 'lpic2-201-6', topicId: 2, question: 'Quelle commande nettoie complètement l\'arborescence des sources du noyau, en supprimant tous les fichiers compilés et le fichier .config ?', options: ['make clean', 'make mrproper', 'make distclean', 'make wipe'], answer: 1, explanation: '`make mrproper` supprime tous les fichiers générés, y compris le `.config` et divers fichiers de sauvegarde, garantissant une arborescence de sources propre.' },
  { id: 'lpic2-201-7', topicId: 2, question: 'Quel est le but de la commande `depmod` ?', options: ['Supprimer un module', 'Générer le fichier modules.dep pour modprobe', 'Afficher les détails des modules', 'Compiler des modules'], answer: 1, explanation: '`depmod` analyse les modules du noyau et génère une liste de dépendances (`modules.dep`) utilisée par `modprobe`.' },
  { id: 'lpic2-201-8', topicId: 2, question: 'Quel outil reconstruit dynamiquement les modules du noyau pour les pilotes tiers (comme Nvidia) lors de l\'installation d\'un nouveau noyau ?', options: ['depmod', 'dracut', 'DKMS', 'kmod'], answer: 2, explanation: 'DKMS (Dynamic Kernel Module Support) est un framework qui recompile les modules externes du noyau chaque fois qu\'un nouveau noyau est installé.' },
  { id: 'lpic2-201-9', topicId: 2, question: 'Comment pouvez-vous visualiser la configuration actuellement active du noyau en cours d\'exécution (si le noyau le permet) ?', options: ['cat /proc/kcore', 'zcat /proc/config.gz', 'cat /sys/kernel/config', 'dmesg | grep config'], answer: 1, explanation: 'Si l\'option `IKCONFIG_PROC` est activée, la configuration du noyau en cours est accessible via `/proc/config.gz`.' },
  { id: 'lpic2-201-10', topicId: 2, question: 'Quelle commande liste tous les modules du noyau actuellement chargés ?', options: ['lsmod', 'modinfo', 'modprobe -l', 'infomod'], answer: 0, explanation: '`lsmod` formate le contenu de `/proc/modules` pour montrer quels modules du noyau sont actuellement chargés en mémoire.' },
  { id: 'lpic2-201-11', topicId: 2, question: 'Quelle est la différence principale entre `initrd` et `initramfs` ?', options: ['initrd est une archive cpio ; initramfs est une image de périphérique bloc', 'initramfs est une archive cpio extraite dans un tmpfs ; initrd est une image de périphérique bloc', 'initrd est uniquement pour l\'UEFI', 'initramfs ne peut pas charger de modules'], answer: 1, explanation: '`initramfs` est une approche plus moderne et simple utilisant une archive cpio compressée chargée dans un tmpfs, évitant les pilotes de périphériques blocs au début du démarrage.' },
  { id: 'lpic2-201-12', topicId: 2, question: 'Quelle commande affiche des informations sur un module du noyau, telles que son auteur, sa description et les paramètres acceptés ?', options: ['lsmod', 'modprobe -d', 'modinfo', 'insmod -i'], answer: 2, explanation: '`modinfo` extrait et affiche les informations du fichier objet du module lui-même.' },
  { id: 'lpic2-201-13', topicId: 2, question: 'Quelle commande lit `sysctl.conf` et applique les paramètres du noyau immédiatement ?', options: ['sysctl -w', 'sysctl -a', 'sysctl -p', 'sysctl -r'], answer: 2, explanation: '`sysctl -p` charge les paramètres de configuration depuis `/etc/sysctl.conf` (ou le fichier spécifié) dans le noyau actif.' },
  { id: 'lpic2-201-14', topicId: 2, question: 'Où `udev` cherche-t-il ses règles personnalisées pour les événements matériels ?', options: ['/etc/udev/rules.d/', '/lib/udev/rules.d/', 'Les deux (A et B)', '/var/run/udev/'], answer: 2, explanation: '`udev` lit les règles par défaut dans `/lib/udev/rules.d/` et les règles personnalisées de l\'administrateur dans `/etc/udev/rules.d/`.' },
  { id: 'lpic2-201-15', topicId: 2, question: 'Quelle commande supprime un module du noyau en cours d\'exécution s\'il n\'est plus utilisé ?', options: ['rmmod', 'insmod -r', 'modprobe -r', 'Les deux (A et C)'], answer: 3, explanation: '`rmmod` et `modprobe -r` peuvent être utilisés pour supprimer des modules ; `modprobe -r` supprime également proprement les dépendances inutilisées.' },

  { id: 'lpic2-202-6', topicId: 3, question: 'Dans systemd, quelle commande définit la cible par défaut sur Graphique (équivalent du runlevel 5) ?', options: ['systemctl set-default graphical.target', 'systemctl isolate graphical.target', 'systemctl default graphical.target', 'ln -s /lib/systemd/system/graphical.target /etc/inittab'], answer: 0, explanation: '`systemctl set-default` modifie la cible de démarrage par défaut en mettant à jour le lien symbolique `/etc/systemd/system/default.target`.' },
  { id: 'lpic2-202-7', topicId: 3, question: 'Lors du démarrage de GRUB 2, quelle touche permet généralement d\'accéder au menu de démarrage pour modifier les paramètres du noyau s\'il est masqué ?', options: ['F8', 'F12', 'Shift ou Esc', 'Entrée'], answer: 2, explanation: 'Maintenir `Shift` (systèmes BIOS) ou appuyer sur `Esc` (systèmes UEFI) interrompt le démarrage de GRUB 2 et affiche le menu.' },
  { id: 'lpic2-202-8', topicId: 3, question: 'Que fait la commande `systemctl isolate` ?', options: ['Redémarre le système', 'Bascule l\'état de fonctionnement actuel vers une nouvelle cible, en arrêtant les services inutiles', 'Désactive les interfaces réseau', 'Effectue un chroot dans un autre environnement'], answer: 1, explanation: '`isolate` fait basculer immédiatement le système vers une nouvelle cible (comme changer de runlevel avec SysV).' },
  { id: 'lpic2-202-9', topicId: 3, question: 'Quel fichier contient les paramètres globaux (comme le délai d\'attente et l\'entrée par défaut) utilisés par grub-mkconfig pour générer la configuration de GRUB 2 ?', options: ['/etc/grub.d/00_header', '/boot/grub/grub.cfg', '/etc/default/grub', '/boot/grub/menu.lst'], answer: 2, explanation: '`/etc/default/grub` contient des variables telles que `GRUB_TIMEOUT` and `GRUB_CMDLINE_LINUX` qui dictent la génération du fichier final.' },
  { id: 'lpic2-202-10', topicId: 3, question: 'Qu\'est-ce que le PXE ?', options: ['Un format de table de partition', 'Une méthode pour démarrer un système d\'exploitation via le réseau en utilisant DHCP et TFTP', 'Un chargeur de démarrage Linux pour ARM', 'Un type d\'unité systemd'], answer: 1, explanation: 'Le Preboot eXecution Environment (PXE) permet aux cartes réseau de récupérer un chargeur de démarrage et un noyau depuis un serveur réseau.' },
  { id: 'lpic2-202-11', topicId: 3, question: 'Quel répertoire contient les scripts modulaires exécutés par `grub-mkconfig` ?', options: ['/etc/default/grub', '/etc/grub.d/', '/boot/grub/scripts/', '/lib/grub/'], answer: 1, explanation: 'Le répertoire `/etc/grub.d/` contient des scripts exécutables (comme 10_linux) qui analysent le système lors de la génération de grub.cfg.' },
  { id: 'lpic2-202-12', topicId: 3, question: 'Qu\'est-ce que `systemd-boot` ?', options: ['Un wrapper SysVinit', 'Un gestionnaire de démarrage UEFI léger', 'Un plugin pour GRUB', 'Un thème Plymouth'], answer: 1, explanation: '`systemd-boot` (anciennement gummiboot) est un gestionnaire de démarrage UEFI simple intégré à systemd.' },
  { id: 'lpic2-202-13', topicId: 3, question: 'Si vous perdez votre mot de passe root, quel paramètre du noyau pouvez-vous passer dans GRUB pour contourner l\'authentification ?', options: ['root=/dev/null', 'init=/bin/bash', 'skip_auth=1', 'runlevel=0'], answer: 1, explanation: 'Ajouter `init=/bin/bash` (ou /bin/sh) monte root et lance immédiatement un shell root sans demander de mot de passe.' },
  { id: 'lpic2-202-14', topicId: 3, question: 'Quelle commande génère un disque RAM initial (initramfs) sur les systèmes Red Hat / CentOS ?', options: ['mkinitcpio', 'mkinitrd / dracut', 'update-initramfs', 'initramfs-build'], answer: 1, explanation: 'Les systèmes basés sur RHEL utilisaient historiquement `mkinitrd` et utilisent maintenant nativement `dracut` pour construire l\'initramfs.' },
  { id: 'lpic2-202-15', topicId: 3, question: 'Sous SysVinit, quel script est généralement responsable de l\'exécution des scripts rc pour le runlevel défini ?', options: ['/etc/rc.local', '/etc/init.d/rc', '/sbin/runlevel', '/bin/sh'], answer: 1, explanation: 'Le script `/etc/init.d/rc` est invoqué par init avec le runlevel en argument pour démarrer/arrêter les services appropriés dans `/etc/rcX.d/`.' },

  { id: 'lpic2-203-6', topicId: 4, question: 'Quelle commande affiche la géométrie matérielle et les partitions d\'un disque ?', options: ['df -h', 'lsblk', 'fdisk -l', 'Les deux (B et C)'], answer: 3, explanation: '`lsblk` et `fdisk -l` décrivent tous deux les périphériques blocs et les partitions (fdisk montre les détails de géométrie).' },
  { id: 'lpic2-203-7', topicId: 4, question: 'Quelle commande convertit un système de fichiers ext3 en ext4 sans perte de données ?', options: ['tune2fs -O extents,uninit_bg,dir_index /dev/sda1', 'mkfs.ext4 /dev/sda1', 'fsck.ext4 -y /dev/sda1', 'parted /dev/sda1 convert ext4'], answer: 0, explanation: '`tune2fs` permet d\'activer des fonctionnalités de système de fichiers sur un disque existant ; l\'ajout des fonctionnalités ext4 le convertit effectivement.' },
  { id: 'lpic2-203-8', topicId: 4, question: 'Quel outil modifie l\'UUId d\'un système de fichiers ext2/ext3/ext4 ?', options: ['uuidgen', 'blkid', 'tune2fs -U', 'xfs_admin'], answer: 2, explanation: '`tune2fs -U [UUID|random] /dev/sdX` modifie l\'identifiant UUID du système de fichiers sur les systèmes ext.' },
  { id: 'lpic2-203-9', topicId: 4, question: 'Quelle option dans `/etc/fstab` monte le système de fichiers en lecture seule ?', options: ['rw', 'ro', 'noexec', 'nosuid'], answer: 1, explanation: 'L\'option `ro` spécifie un montage en mode lecture seule (Read-Only).' },
  { id: 'lpic2-203-10', topicId: 4, question: 'Quelle commande fournit des informations sur l\'état et la fragmentation d\'un système de fichiers XFS ?', options: ['xfs_repair', 'xfs_info', 'xfs_db', 'Aucune des réponses précédentes'], answer: 1, explanation: '`xfs_info` affiche les détails de géométrie et de disposition d\'un système de fichiers XFS monté.' },
  { id: 'lpic2-203-11', topicId: 4, question: 'Comment pouvez-vous effacer de manière sécurisée un disque dur (/dev/sdb) en l\'écrasant avec des données aléatoires ?', options: ['dd if=/dev/urandom of=/dev/sdb bs=1M', 'rm -rf /dev/sdb', 'mkfs.ext4 /dev/sdb', 'fdisk -w /dev/sdb'], answer: 0, explanation: 'Utiliser `dd` pour lire depuis `/dev/urandom` écrase physiquement le disque cible avec des données binaires imprévisibles.' },
  { id: 'lpic2-203-12', topicId: 4, question: 'Que fait la commande `badblocks` ?', options: ['Formate le disque', 'Recherche les secteurs physiquement endommagés sur un périphérique', 'Répare le journal du système de fichiers', 'Identifie la RAM défectueuse'], answer: 1, explanation: '`badblocks` effectue des tests de lecture/écriture sur les secteurs pour identifier les blocs physiquement inutilisables sur un support de stockage.' },
  { id: 'lpic2-203-13', topicId: 4, question: 'Quelle commande Btrfs crée un instantané (snapshot) en lecture-écriture d\'un sous-volume ?', options: ['btrfs subvolume snapshot', 'btrfs snap create', 'lvcreate -s', 'btrfs-image'], answer: 0, explanation: '`btrfs subvolume snapshot <source> <dest>` crée un instantané de type Copy-on-Write.' },
  { id: 'lpic2-203-14', topicId: 4, question: 'Qu\'est-ce qu\'`autofs` ?', options: ['Un outil pour formater des disques', 'Un démon qui monte automatiquement les systèmes de fichiers à la demande', 'Un remplacement pour GRUB', 'Un routeur de paquets réseau'], answer: 1, explanation: '`autofs` permet le montage automatique (monter uniquement lorsqu\'un utilisateur accède à un répertoire spécifique) et le démontage automatique.' },
  { id: 'lpic2-203-15', topicId: 4, question: 'Quelle commande de création de supports optiques crée une image de système de fichiers ISO9660 ?', options: ['cdrecord', 'mkisofs', 'growisofs', 'wodim'], answer: 1, explanation: '`mkisofs` (ou genisoimage) prend une arborescence de répertoires et génère un fichier de disposition ISO9660 prêt à être gravé.' },

  { id: 'lpic2-204-6', topicId: 5, question: 'En LVM, comment réduire en toute sécurité la taille d\'un volume logique ?', options: ['lvresize -L -10G /dev/vg/lv', 'Réduire d\'abord le système de fichiers à l\'intérieur du LV, puis réduire le LV', 'Réduire d\'abord le LV, puis réduire le système de fichiers', 'On ne peut pas réduire un LV'], answer: 1, explanation: 'Il faut réduire le système de fichiers (ex: resize2fs) AVANT de réduire le LV pour éviter de corrompre les limites des données.' },
  { id: 'lpic2-204-7', topicId: 5, question: 'Lors de la gestion d\'un array RAID 5 logiciel avec `mdadm`, que se passe-t-il si un disque tombe en panne ?', options: ['Les données sont définitivement perdues', 'L\'array fonctionne en mode dégradé en utilisant la parité pour calculer les données manquantes', 'Le système subit immédiatement un kernel panic', 'L\'array bascule en RAID 0'], answer: 1, explanation: 'Le RAID 5 peut tolérer exactement une panne de disque, fonctionnant en "mode dégradé" jusqu\'à la reconstruction.' },
  { id: 'lpic2-204-8', topicId: 5, question: 'Quelle commande initie une session iSCSI pour découvrir les cibles (targets) on a server?', options: ['iscsiadm -m discovery -t sendtargets -p <IP>', 'iscsid --scan', 'mount -t iscsi', 'lvscan'], answer: 0, explanation: '`iscsiadm` est l\'outil en ligne de commande pour interagir avec l\'initiateur open-iscsi pour la découverte et la connexion.' },
  { id: 'lpic2-204-9', topicId: 5, question: 'Que montre la commande LVM `vgdisplay` ?', options: ['Uniquement les volumes physiques', 'Uniquement les volumes logiques', 'Les attributs du Volume Group tels que la taille totale, les PEs libres et les PEs alloués', 'Les UUID des systèmes de fichiers'], answer: 2, explanation: '`vgdisplay` affiche les métadonnées concernant les Volume Groups, y compris les détails de capacité des Physical Extents (PE).' },
  { id: 'lpic2-204-10', topicId: 5, question: 'Comment ajouter un disque de rechange (spare) à un array RAID `mdadm` existant (/dev/md0) ?', options: ['mdadm --add /dev/md0 /dev/sdX', 'mdadm --grow /dev/md0 --size=spare', 'mdadm --create /dev/md0 /dev/sdX', 'On ne peut pas ajouter de spares aux arrays actifs'], answer: 0, explanation: 'L\'option `--add` (ou `-a`) ajoute à chaud un périphérique de rechange à un array existant.' },
  { id: 'lpic2-204-11', topicId: 5, question: 'Quel est le but des instantanés (snapshots) LVM ?', options: ['Créer des sauvegardes permanentes sur bande', 'Capturer l\'état d\'un volume logique instantanément (Copy-on-Write) pour des sauvegardes cohérentes', 'Accélérer les lectures disque', 'Convertir ext4 en xfs'], answer: 1, explanation: 'Les instantanés suivent les changements via CoW, ce qui vous permet de sauvegarder un état figé dans le temps d\'un volume sans interruption de service.' },
  { id: 'lpic2-204-12', topicId: 5, question: 'Dans un environnement iSCSI, qu\'est-ce qu\'un IQN ?', options: ['Internal Query Network', 'iSCSI Qualified Name', 'Internet Quota Node', 'Initial Queue Number'], answer: 1, explanation: 'L\'iSCSI Qualified Name (IQN) est un identifiant unique mondial pour les initiateurs et les cibles iSCSI.' },
  { id: 'lpic2-204-13', topicId: 5, question: 'Quelle option de `hdparm` permet d\'obtenir ou de définir le délai de mise en veille (spindown) d\'un disque ?', options: ['-S', '-y', '-Z', '-B'], answer: 0, explanation: '`hdparm -S` définit le délai d\'attente avant la mise en veille des plateaux (spindown) pour un disque IDE/SATA/SAS.' },
  { id: 'lpic2-204-14', topicId: 5, question: 'Quel fichier stocke dynamiquement l\'état et les détails des arrays RAID logiciels de `mdadm` ?', options: ['/etc/mdadm.conf', '/proc/mdstat', '/var/log/raid.log', '/sys/block/raid'], answer: 1, explanation: '`/proc/mdstat` fournit un résumé en temps réel des arrays RAID logiciels du noyau et de leur état de synchronisation.' },
  { id: 'lpic2-204-15', topicId: 5, question: 'Quel composant LVM est créé directement sur une partition de disque brute ?', options: ['Volume Logique (LV)', 'Volume Group (VG)', 'Volume Physique (PV)', 'Volume Extent (VE)'], answer: 2, explanation: 'Un Volume Physique (PV) est la structure de base LVM créée directement sur un disque ou une partition.' },

  // --- NOUVEAU BATCH 2 (Thèmes 205-209) ---
  { id: 'lpic2-205-6', topicId: 6, question: 'Quel fichier de zone DNS contient les enregistrements de pointeur (PTR) pour la résolution inverse ?', options: ['db.linux.com', 'db.192.168.1', 'named.conf', 'resolv.conf'], answer: 1, explanation: 'Les fichiers de zone inverse (souvent nommés selon le réseau) mappent les adresses IP aux noms d\'hôte via les enregistrements PTR.' },
  { id: 'lpic2-205-7', topicId: 6, question: 'Quel est le but de la directive `directory` dans `named.conf` ?', options: ['Définit la racine du système de fichiers pour BIND', 'Spécifie le répertoire de travail où se trouvent les fichiers de zone', 'Liste les répertoires pour les logs', 'Définit le chemin vers le binaire named'], answer: 1, explanation: 'L\'option `directory` dans la clause `options` définit le chemin de base pour tous les fichiers de zone relatifs.' },
  { id: 'lpic2-205-8', topicId: 6, question: 'Quelle commande vérifie la syntaxe du fichier de configuration principal de BIND ?', options: ['named-checkzone', 'named-checkconf', 'bind-verify', 'systemctl status named'], answer: 1, explanation: '`named-checkconf` analyse `named.conf` pour détecter les erreurs de syntaxe avant de recharger le service.' },
  { id: 'lpic2-205-9', topicId: 6, question: 'Quel type d\'enregistrement DNS est utilisé pour spécifier l\'adresse IPv6 d\'un hôte ?', options: ['A', 'AAAA', 'CNAME', 'MX'], answer: 1, explanation: 'L\'enregistrement `AAAA` (quad-A) mappe un nom d\'hôte à une adresse IPv6 de 128 bits.' },
  { id: 'lpic2-205-10', topicId: 6, question: 'Dans une configuration BIND, que fait l\'option `forwarders { 8.8.8.8; };` ?', options: ['Autorise le transfert de zone vers 8.8.8.8', 'Définit 8.8.8.8 comme serveur maître', 'Indique au serveur d\'interroger 8.8.8.8 pour les requêtes qu\'il ne peut pas résoudre localement', 'Bloque tout le trafic venant de 8.8.8.8'], answer: 2, explanation: 'La directive `forwarders` spécifie les serveurs DNS externes auxquels les requêtes récursives doivent être envoyées.' },
  { id: 'lpic2-205-11', topicId: 6, question: 'Comment pouvez-vous capturer les paquets réseau avec `tcpdump` et les enregistrer dans un fichier nommé `capture.pcap` ?', options: ['tcpdump > capture.pcap', 'tcpdump -f capture.pcap', 'tcpdump -w capture.pcap', 'tcpdump -o capture.pcap'], answer: 2, explanation: 'Le drapeau `-w` (write) demande à `tcpdump` d\'écrire les paquets bruts dans un fichier spécifié.' },
  { id: 'lpic2-205-12', topicId: 6, question: 'Quel sigle DNS définit le serveur de noms faisant autorité et les paramètres de temporisation pour une zone ?', options: ['NS', 'SOA', 'TXT', 'CNAME'], answer: 1, explanation: 'L\'enregistrement Start of Authority (SOA) contient des informations cruciales sur la zone, y compris le serveur primaire et les intervalles de rafraîchissement.' },
  { id: 'lpic2-205-13', topicId: 6, question: 'Quelle utilité a l\'outil `rndc` ?', options: ['Compiler BIND depuis les sources', 'Administrer à distance ou localement le démon named (rechargement, stats, arrêt)', 'Générer des clés DNSSEC', 'Analyser les logs Apache'], answer: 1, explanation: '`rndc` est l\'utilitaire de contrôle pour le serveur de noms BIND.' },
  { id: 'lpic2-205-14', topicId: 6, question: 'Dans un fichier de zone, que signifie le symbole `@` ?', options: ['Une erreur de syntaxe', 'L\'adresse e-mail de l\'administrateur', 'Le nom de domaine actuel défini par l\'origine ($ORIGIN)', 'Une wildcard pour tous les sous-domaines'], answer: 2, explanation: 'Le symbole `@` est un raccourci représentant le domaine actuel (l\'origine) de la zone.' },
  { id: 'lpic2-205-15', topicId: 6, question: 'Quel enregistrement DNS permet de créer un alias d\'un nom vers un autre nom (Canonical Name) ?', options: ['PTR', 'CNAME', 'ALIAS', 'MX'], answer: 1, explanation: 'L\'enregistrement `CNAME` mappe un alias (nom alternatif) vers le nom canonique (vrai nom).' },

  { id: 'lpic2-206-6', topicId: 7, question: 'Dans Apache, quelle directive définit le répertoire racine à partir duquel les fichiers sont servis ?', options: ['RootDirectory', 'DocumentRoot', 'ServerPath', 'VirtualHost'], answer: 1, explanation: '`DocumentRoot` spécifie le répertoire système contenant les documents HTML.' },
  { id: 'lpic2-206-7', topicId: 7, question: 'Quelle commande active un module Apache sur un système Debian/Ubuntu ?', options: ['apachectl enable-module', 'a2enmod', 'mods-enabled', 'systemctl load-mod'], answer: 1, explanation: '`a2enmod` (Apache 2 Enable Module) crée les liens symboliques nécessaires pour activer un module.' },
  { id: 'lpic2-206-8', topicId: 7, question: 'Quel fichier de configuration Nginx est généralement utilisé pour définir les blocs `server` individuels sur Debian/Ubuntu ?', options: ['/etc/nginx/nginx.conf', '/etc/nginx/sites-available/', '/etc/nginx/conf.d/', 'Les deux (B et C)'], answer: 3, explanation: 'Nginx utilise couramment `sites-available` (activé via sites-enabled) ou `conf.d/` pour modulariser les hôtes virtuels.' },
  { id: 'lpic2-206-9', topicId: 7, question: 'Dans Nginx, quelle directive est l\'équivalent de `DocumentRoot` d\'Apache ?', options: ['site_root', 'root', 'path', 'index'], answer: 1, explanation: 'La directive `root` dans Nginx définit le répertoire de base pour les requêtes.' },
  { id: 'lpic2-206-10', topicId: 7, question: 'Quelle directive Apache limite l\'accès à un répertoire spécifique en fonction de l\'adresse IP ?', options: ['Require ip', 'Allow from', 'Order deny,allow', 'Toutes les réponses précédentes (selon la version)'], answer: 3, explanation: 'Apache 2.2 utilisait `Allow/Deny`, tandis qu\'Apache 2.4 utilise la syntaxe `Require`.' },
  { id: 'lpic2-206-11', topicId: 7, question: 'Comment rediriger tout le trafic HTTP vers HTTPS dans un bloc server Nginx ?', options: ['redirect https', 'return 301 https://$host$request_uri;', 'rewrite ssl on;', 'proxy_pass https;'], answer: 1, explanation: '`return 301` est la méthode la plus efficace pour effectuer une redirection permanente dans Nginx.' },
  { id: 'lpic2-206-12', topicId: 7, question: 'Quelle commande recharge la configuration d\'Apache sans déconnecter les sessions actives ?', options: ['systemctl stop apache2', 'apachectl restart', 'apache2ctl graceful', 'service apache2 stop'], answer: 2, explanation: 'Un redémarrage "graceful" (ou `systemctl reload`) demande aux processus enfants de s\'arrêter après avoir servi les requêtes en cours.' },
  { id: 'lpic2-206-13', topicId: 7, question: 'Quel est le but du module Apache `mod_proxy` ?', options: ['Mettre en cache les fichiers statiques', 'Permettre à Apache de fonctionner comme un proxy inverse ou une passerelle', 'Gérer l\'authentification LDAP', 'Chiffrer le trafic avec SSL'], answer: 1, explanation: '`mod_proxy` permet à Apache de relayer les requêtes vers d\'autres serveurs (comme des serveurs d\'application).' },
  { id: 'lpic2-206-14', topicId: 7, question: 'Dans Nginx, quel bloc est utilisé pour traiter les requêtes basées sur des motifs d\'URL (URIs) ?', options: ['server', 'location', 'http', 'upstream'], answer: 1, explanation: 'Le bloc `location` permet de configurer le traitement des requêtes pour des chemins spécifiques.' },
  { id: 'lpic2-206-15', topicId: 7, question: 'Quelle directive Apache définit l\'adresse e-mail qui sera incluse dans les messages d\'erreur envoyés au client ?', options: ['ServerAdmin', 'AdminEmail', 'ErrorMail', 'Contact'], answer: 0, explanation: '`ServerAdmin` définit l\'adresse de contact affichée sur les pages d\'erreur générées par le serveur.' },

  { id: 'lpic2-207-6', topicId: 8, question: 'Dans NFS, quelle option dans `/etc/exports` permet à l\'utilisateur root sur le client d\'avoir les privilèges root sur le serveur ?', options: ['root_allow', 'no_root_squash', 'all_squash', 'rw,sync'], answer: 1, explanation: 'Par défaut (root_squash), root est mappé sur l\'utilisateur `nobody`. `no_root_squash` désactive ce comportement.' },
  { id: 'lpic2-207-7', topicId: 8, question: 'Quelle commande Samba vérifie la syntaxe du fichier `smb.conf` ?', options: ['smbcheck', 'testparm', 'samba-tool config', 'net conf verify'], answer: 1, explanation: '`testparm` est l\'utilitaire standard pour valider la configuration de Samba.' },
  { id: 'lpic2-207-8', topicId: 8, question: 'Quel port est principalement utilisé par le service NFSv4 ?', options: ['111 (portmapper)', '445 (microsoft-ds)', '2049', '139 (netbios)'], answer: 2, explanation: 'NFSv4 simplifie la configuration réseau en utilisant presque exclusivement le port TCP 2049.' },
  { id: 'lpic2-207-9', topicId: 8, question: 'Dans un partage Samba, que fait l\'option `writable = yes` ?', options: ['Autorise l\'exécution de scripts', 'Permet aux utilisateurs de créer et modifier des fichiers dans le partage', 'Active le chiffrement du partage', 'Définit le partage comme public'], answer: 1, explanation: '`writable = yes` (ou `read only = no`) donne les droits d\'écriture sur le partage.' },
  { id: 'lpic2-207-10', topicId: 8, question: 'Quelle commande affiche les exportations NFS actives sur un serveur distant ?', options: ['netstat -nfs', 'showmount -e <IP>', 'nfsstat', 'exportfs -v'], answer: 1, explanation: '`showmount -e` interroge le démon mountd sur l\'hôte distant pour lister les systèmes de fichiers exportés.' },
  { id: 'lpic2-207-11', topicId: 8, question: 'Quel démon Samba est responsable de la navigation sur le réseau et de la résolution de noms NetBIOS ?', options: ['smbd', 'nmbd', 'winbindd', 'samba-ad'], answer: 1, explanation: '`nmbd` gère les requêtes de nom NetBIOS sur IP et gère les listes de navigation réseau.' },
  { id: 'lpic2-207-12', topicId: 8, question: 'Comment appliquer les modifications faites dans `/etc/exports` sans redémarrer le serveur NFS ?', options: ['nfs reload', 'exportfs -a', 'systemctl restart nfs-kernel-server', 'Les deux (B et C)'], answer: 3, explanation: '`exportfs -a` (ou -r) synchronise la table d\'exportation du noyau avec le fichier sans arrêter le service.' },
  { id: 'lpic2-207-13', topicId: 8, question: 'Dans Samba, quelle directive mappe les utilisateurs Linux aux noms d\'utilisateur Windows ?', options: ['user map', 'username map', 'alias file', 'winbind map'], answer: 1, explanation: '`username map` définit un fichier contenant les correspondances entre noms d\'utilisateur Linux et Windows.' },
  { id: 'lpic2-207-14', topicId: 8, question: 'Quelle version de NFS est "stateful" et n\'utilise plus le portmapper UDP ?', options: ['NFSv2', 'NFSv3', 'NFSv4', 'NFSv5'], answer: 2, explanation: 'NFSv4 est un protocole orienté état (stateful) conçu pour mieux fonctionner avec les pare-feu.' },
  { id: 'lpic2-207-15', topicId: 8, question: 'Quel outil Samba permet de gérer les comptes d\'utilisateurs et les mots de passe dans la base de données locale TDB ?', options: ['smbpasswd', 'pdbedit', 'Les deux (A et B)', 'useradd'], answer: 2, explanation: '`smbpasswd` est l\'outil classique, tandis que `pdbedit` offre une gestion plus granulaire du backend SAM (Security Account Manager).' },

  { id: 'lpic2-208-6', topicId: 9, question: 'Quelle directive dans `dhcpd.conf` spécifie l\'adresse IP du routeur par défaut pour les clients ?', options: ['option home-router', 'option gateways', 'option routers', 'default-gateway'], answer: 2, explanation: 'L\'option `routers` définit la passerelle par défaut transmise aux clients DHCP.' },
  { id: 'lpic2-208-7', topicId: 9, question: 'Quel est le but du service Squid ?', options: ['Servir de serveur de messagerie', 'Fournir un proxy cache pour le web (HTTP/HTTPS/FTP)', 'Héberger des bases de données', 'Gérer les connexions SSH'], answer: 1, explanation: 'Squid est un proxy de mise en cache haute performance utilisé pour optimiser et filtrer le trafic web.' },
  { id: 'lpic2-208-8', topicId: 9, question: 'Dans une configuration DHCP, comment assigner toujours la même adresse IP à un hôte spécifique ?', options: ['En créant une déclaration `host` avec l\'option `fixed-address` et l\'adresse MAC', 'En augmentant le temps de bail (lease time)', 'En utilisant la directive `static-ip` dans la plage (range)', 'C\'est impossible avec DHCP'], answer: 0, explanation: 'Les réservations statiques lient une adresse MAC spécifique à une adresse IP via le bloc `host`.' },
  { id: 'lpic2-208-9', topicId: 9, question: 'Quelle directive Squid contrôle l\'accès basé sur des listes de contrôle d\'accès (ACL) définies ?', options: ['acl_access', 'http_access', 'proxy_allow', 'filter_access'], answer: 1, explanation: '`http_access allow/deny <nom_de_l_acl>` est la directive principale pour appliquer les politiques de filtrage.' },
  { id: 'lpic2-208-10', topicId: 9, question: 'Quelle commande permet de visualiser les baux (leases) actuellement attribués par le serveur DHCP ISC ?', options: ['cat /var/lib/dhcp/dhcpd.leases', 'dhcp-status', 'systemctl status dhcpd', 'showleases'], answer: 0, explanation: 'Le serveur DHCP stocke l\'historique et l\'état des baux actifs dans le fichier texte `dhcpd.leases`.' },
  { id: 'lpic2-208-11', topicId: 9, question: 'Comment appelle-t-on un proxy Squid qui intercepte le trafic web sans que le client n\'ait besoin de configuration manuelle ?', options: ['Proxy inverse', 'Proxy transparent (ou interceptant)', 'Proxy cascade', 'Passerelle applicative'], answer: 1, explanation: 'Un proxy transparent intercepte les requêtes au niveau réseau (via iptables/nftables) de manière invisible pour l\'utilisateur.' },
  { id: 'lpic2-208-12', topicId: 9, question: 'Quelle directive Squid définit la quantité de RAM à utiliser pour le cache mémoire des objets ?', options: ['cache_mem', 'memory_replacement_policy', 'maximum_object_size', 'ram_cache'], answer: 0, explanation: '`cache_mem` spécifie la limite de mémoire vive dédiée au stockage des objets fréquemment consultés.' },
  { id: 'lpic2-208-13', topicId: 9, question: 'Quel est l\'ordre correct des messages dans le processus d\'attribution DHCP ?', options: ['Request, Discover, Offer, Ack', 'Discover, Offer, Request, Ack', 'Offer, Discover, Ack, Request', 'Discover, Request, Offer, Ack'], answer: 1, explanation: 'Le cycle DORA : Discover (Client), Offer (Serveur), Request (Client), Acknowledgment (Serveur).' },
  { id: 'lpic2-208-14', topicId: 9, question: 'Quelle directive Apache dans un bloc `<VirtualHost>` spécifie les noms de domaine auxquels l\'hôte répondra ?', options: ['DNSName', 'Hostname', 'ServerName et ServerAlias', 'Domain'], answer: 2, explanation: '`ServerName` assigne le domaine principal, et `ServerAlias` spécifie les noms d\'hôte alternatifs.' },
  { id: 'lpic2-208-15', topicId: 9, question: 'Que fait la commande `squid -k reconfigure` ?', options: ['Tue brutalement le processus squid', 'Vide entièrement le cache', 'Envoie un signal au processus Squid en cours pour recharger le fichier squid.conf sans déconnecter les clients', 'Télécharge des mises à jour'], answer: 2, explanation: 'Tout comme un reload Nginx, `-k reconfigure` est la méthode sûre pour appliquer les changements de configuration.' },

  { id: 'lpic2-209-6', topicId: 10, question: 'Quelle commande affiche les connexions actives et les fichiers verrouillés sur un serveur Samba ?', options: ['smbstatus', 'testparm', 'smbclient', 'netstat -smb'], answer: 0, explanation: '`smbstatus` rapporte les connexions Samba actuelles, incluant les utilisateurs, les machines et les fichiers verrouillés.' },
  { id: 'lpic2-209-7', topicId: 10, question: 'Quel est le rôle du protocole Dovecot dans une architecture de messagerie ?', options: ['Relayer les messages vers Internet (MTA)', 'Fournir un service de récupération de messages via IMAP/POP3 (MDA/MS)', 'Filtrer les spams', 'Gérer les listes de diffusion'], answer: 1, explanation: 'Dovecot est un serveur de messagerie sécurisé qui permet aux utilisateurs de lire leurs courriels via IMAP ou POP3.' },
  { id: 'lpic2-209-8', topicId: 10, question: 'Comment s\'appelle le fichier de configuration principal de Postfix ?', options: ['postfix.conf', 'mail.cf', 'main.cf', 'master.cf'], answer: 2, explanation: '`main.cf` contient la plupart des paramètres de configuration du serveur Postfix.' },
  { id: 'lpic2-209-9', topicId: 10, question: 'Quelle commande Postfix traite le fichier `/etc/aliases` et met à jour la base de données alias.db ?', options: ['postmap', 'newaliases', 'postfix reload', 'postalias'], answer: 1, explanation: '`newaliases` est le lien standard vers l\'utilitaire qui reconstruit la base de données des alias de messagerie.' },
  { id: 'lpic2-209-10', topicId: 10, question: 'Dans Postfix, quel démon est responsable de la gestion du transport et de la livraison effective des messages ?', options: ['smtpd', 'qmgr', 'master', 'cleanup'], answer: 1, explanation: '`qmgr` (queue manager) est le cœur de Postfix, orchestrant le mouvement des messages dans les files d\'attente.' },
  { id: 'lpic2-209-11', topicId: 10, question: 'Quel protocole est utilisé par un serveur de messagerie pour envoyer des courriels à un autre serveur sur Internet ?', options: ['IMAP', 'POP3', 'SMTP', 'HTTP'], answer: 2, explanation: 'Le Simple Mail Transfer Protocol (SMTP) est le standard pour le transfert de courriels.' },
  { id: 'lpic2-209-12', topicId: 10, question: 'Quelle directive Postfix définit les réseaux "de confiance" autorisés à relayer des messages sans authentification ?', options: ['mynetworks', 'trusted_hosts', 'relay_domains', 'allowed_ips'], answer: 0, explanation: 'La directive `mynetworks` liste les réseaux pour lesquels Postfix acceptera de relayer du courrier.' },
  { id: 'lpic2-209-13', topicId: 10, question: 'Quel est le but d\'un mécanisme de "Greylisting" ?', options: ['Chiffrer les e-mails', 'Réduite le spam en rejetant temporairement les e-mails provenant de serveurs inconnus', 'Archiver les e-mails', 'Scanner les pièces jointes pour les virus'], answer: 1, explanation: 'Le greylisting tire parti du fait que la plupart des émetteurs de spam ne réessaient pas l\'envoi après un échec temporaire, contrairement aux serveurs légitimes.' },
  { id: 'lpic2-209-14', topicId: 10, question: 'Quel fichier de configuration Postfix définit les processus et services (comme smtpd, pickup) qui composent le système ?', options: ['main.cf', 'aliases', 'master.cf', 'transport'], answer: 2, explanation: '`master.cf` définit les processus résidents de Postfix et la manière dont ils s\'exécutent.' },
  { id: 'lpic2-209-15', topicId: 10, question: 'Quelle commande affiche la file d\'attente (mail queue) de Postfix ?', options: ['mailq', 'postqueue -p', 'Les deux (A et B)', 'postfix status'], answer: 2, explanation: '`mailq` et `postqueue -p` affichent tous deux la liste des messages en attente de livraison.' },
  { id: 'lpic2-209-16', topicId: 10, question: 'Lors de l\'examen de `/etc/exports`, que fait le paramètre `no_root_squash` ?', options: ['Il empêche totalement l\'accès root', 'Il permet à l\'utilisateur root distant de conserver ses privilèges root sur le répertoire exporté', 'Il compresse les fichiers accédés par root', 'Il mappe root vers l\'utilisateur nobody'], answer: 1, explanation: 'Normalement, NFS écrase (squash) les requêtes root vers un UID anonyme. `no_root_squash` annule ce comportement, ce qui présente un risque de sécurité important s\'il est utilisé sans précaution.' },

  // --- NOUVEAU BATCH 3 (Thèmes 210-212) ---
  { id: 'lpic2-210-6', topicId: 11, question: 'Dans la configuration du serveur DHCP ISC (`dhcpd.conf`), quel paramètre définit la durée par défaut d\'attribution d\'une IP à un client s\'il ne demande pas de durée spécifique ?', options: ['max-lease-time', 'default-lease-time', 'lease-duration', 'expire-time'], answer: 1, explanation: '`default-lease-time` est la durée d\'allocation standard en secondes.' },
  { id: 'lpic2-210-7', topicId: 11, question: 'Quel démon DHCP ISC crée le journal centralisé des IP louées, stockant ainsi l\'état entre les redémarrages ?', options: ['/etc/dhcp/dhcpd.conf', '/var/lib/dhclient/dhclient.leases', '/var/lib/dhcp/dhcpd.leases', '/var/log/dhcpd.log'], answer: 2, explanation: 'Le fichier `dhcpd.leases` sert de base de données pour le suivi des allocations actives.' },
  { id: 'lpic2-210-8', topicId: 11, question: 'Quels sont les quatre groupes de gestion au sein d\'un fichier de configuration de module PAM ?', options: ['allow, deny, warn, critical', 'auth, account, password, session', 'user, group, other, root', 'login, shell, network, local'], answer: 1, explanation: 'PAM organise les règles en auth (identité), account (validité), password (mise à jour des identifiants) et session (configuration/nettoyage).' },
  { id: 'lpic2-210-9', topicId: 11, question: 'Dans une pile PAM, que se passe-t-il si un module marqué comme `requisite` échoue ?', options: ['La pile renvoie immédiatement un échec sans exécuter d\'autres modules', 'L\'échec est enregistré, mais le module suivant est testé', 'L\'utilisateur est dirigé vers un shell limité', 'L\'utilisateur est invité à saisir un CAPTCHA'], answer: 0, explanation: 'Contrairement à `required`, `requisite` provoque un échec instantané, évitant tout traitement ultérieur.' },
  { id: 'lpic2-210-10', topicId: 11, question: 'Par défaut, sur quel port TCP fonctionne le protocole LDAP non chiffré ?', options: ['110', '389', '636', '3306'], answer: 1, explanation: 'LDAP communique via le port TCP 389, tandis que LDAPS (LDAP sur SSL) utilise le port 636.' },
  { id: 'lpic2-210-11', topicId: 11, question: 'Quel démon est le moteur central de la suite serveur OpenLDAP ?', options: ['ldap_agent', 'named', 'slapd', 'sssd'], answer: 2, explanation: '`slapd` signifie Stand-Alone LDAP Daemon.' },
  { id: 'lpic2-210-12', topicId: 11, question: 'Quel utilitaire en ligne de commande interroge un annuaire LDAP à l\'aide de filtres ?', options: ['ldapquery', 'ldapsearch', 'ldaplookup', 'ldapfind'], answer: 1, explanation: '`ldapsearch` ouvre une connexion à un serveur LDAP, s\'y lie et effectue une recherche à l\'aide d\'un filtre donné.' },
  { id: 'lpic2-210-13', topicId: 11, question: 'Quel démon moderne est largement utilisé sous Linux pour mettre en cache les identifiants et gérer les connexions aux annuaires centraux comme LDAP ou Active Directory ?', options: ['nscd', 'sssd', 'pam_unix', 'winbind'], answer: 1, explanation: 'Le System Security Services Daemon (SSSD) intègre le système aux annuaires centraux distants et fournit une mise en cache hors ligne.' },
  { id: 'lpic2-210-14', topicId: 11, question: 'Dans OpenVPN, le routage de tout le trafic internet client via le VPN nécessite de transmettre quelle directive spécifique au client ?', options: ['push "route 0.0.0.0 0.0.0.0"', 'push "redirect-gateway def1"', 'push "default-route"', 'route-all'], answer: 1, explanation: '`redirect-gateway def1` modifie la table de routage par défaut du client pour pointer vers le tunnel VPN.' },
  { id: 'lpic2-210-15', topicId: 11, question: 'Quelle commande force un client Linux à libérer manuellement son adresse IP louée par DHCP et à arrêter le démon ?', options: ['dhclient -x', 'dhclient -r', 'ifdown eth0', 'ip addr flush'], answer: 1, explanation: '`dhclient -r` libère explicitement le bail actuel auprès du serveur et arrête le démon client.' },
  { id: 'lpic2-210-16', topicId: 11, question: 'Quelle est l\'extension standard pour le fichier d\'autorité de certification utilisé pour authentifier les clients OpenVPN ?', options: ['.key', '.crt', '.csr', '.ca'], answer: 1, explanation: 'Les certificats (clés publiques) utilisent généralement l\'extension `.crt` ou `.pem`.' },

  { id: 'lpic2-211-6', topicId: 12, question: 'Quelle commande affiche le contenu actuel de l\'attente de livraison (mail queue) de Postfix ?', options: ['mailq', 'postqueue -p', 'Les deux (A et B)', 'qstat'], answer: 2, explanation: '`mailq` est généralement un lien symbolique vers `postqueue -p`, qui affiche la file d\'attente.' },
  { id: 'lpic2-211-7', topicId: 12, question: 'Que fait la commande Postfix `postsuper -d ALL` ?', options: ['Supprime tous les messages de l\'attente de livraison', 'Télécharge tous les messages du MTA', 'Déploie une nouvelle configuration superviseur', 'Désactive le serveur de messagerie'], answer: 0, explanation: '`postsuper` gère la file d\'attente Postfix ; `-d ALL` supprime de manière irrécupérable tous les messages de la file.' },
  { id: 'lpic2-211-8', topicId: 12, question: 'Quel paramètre dans `main.cf` définit les noms de domaine pour lesquels Postfix se considère comme la destination finale ?', options: ['myhostname', 'mynetworks', 'mydestination', 'relay_domains'], answer: 2, explanation: 'Les messages adressés aux domaines listés dans `mydestination` sont livrés localement.' },
  { id: 'lpic2-211-9', topicId: 12, question: 'Si vous souhaitez que Postfix rejette globalement les e-mails provenant d\'adresses IP de spammeurs connus, quelle directive configureriez-vous pour utiliser les listes de blocage DNS (DNSBL) ?', options: ['smtpd_recipient_restrictions', 'smtpd_client_restrictions', 'header_checks', 'virtual_alias_maps'], answer: 1, explanation: '`smtpd_client_restrictions = reject_rbl_client zen.spamhaus.org` évalue l\'IP de connexion avant toute transaction.' },
  { id: 'lpic2-211-10', topicId: 12, question: 'Quel port est historiquement réservé au protocole POP3 (non chiffré) ?', options: ['25', '110', '143', '993'], answer: 1, explanation: 'Le protocole POP (Post Office Protocol) version 3 fonctionne sur le port TCP 110.' },
  { id: 'lpic2-211-11', topicId: 12, question: 'Dans Dovecot, quel est le port par défaut pour IMAPS (IMAP sécurisé via SSL/TLS) ?', options: ['143', '465', '587', '993'], answer: 3, explanation: 'IMAPS utilise TLS implicitement sécurisé sur le port TCP 993.' },
  { id: 'lpic2-211-12', topicId: 12, question: 'Quel langage de script MDA est considéré comme l\'alternative moderne et standardisée à Procmail, conçu spécifiquement pour s\'intégrer proprement à Dovecot ?', options: ['Bash', 'Python', 'Sieve', 'Perl'], answer: 2, explanation: 'Sieve est un langage de script hautement sécurisé et standardisé pour le filtrage des e-mails au niveau MTA/MDA.' },
  { id: 'lpic2-211-13', topicId: 12, question: 'Où les règles (recipes) Procmail sont-elles généralement définies pour chaque utilisateur ?', options: ['/etc/procmail.conf', '~/.procmailrc', '/var/spool/mail/recipes', '~/.mailfilter'], answer: 1, explanation: 'Les utilisateurs créent leurs propres règles de routage de courrier dans `.procmailrc` dans leur répertoire personnel.' },
  { id: 'lpic2-211-14', topicId: 12, question: 'Quelle est la fonction du paramètre `mynetworks` dans Postfix ?', options: ['Il bloque le spam de ces réseaux', 'Il définit la liste des réseaux locaux autorisés à relayer des messages via le serveur vers des domaines externes', 'Il mappe les adresses IP locales', 'Il définit les interfaces IP sur lesquelles Postfix écoute'], answer: 1, explanation: 'Les clients provenant d\'adresses IP correspondant à `mynetworks` sont implicitement autorisés à relayer du courrier.' },
  { id: 'lpic2-211-15', topicId: 12, question: 'Quelle commande force Postfix à tenter immédiatement la livraison de tous les messages différés se trouvant dans la file d\'attente ?', options: ['postsuper -r', 'postfix flush', 'postqueue -f', 'mailq -f'], answer: 2, explanation: '`postqueue -f` parcourt la file d\'attente de messagerie et tente un vidage (flush) immédiat.' },
  { id: 'lpic2-211-16', topicId: 12, question: 'Que configure la directive Postfix `virtual_alias_maps` ?', options: ['Mappe les domaines virtuels sur des adresses IP physiques', 'Redirige les e-mails d\'une adresse spécifique (ex: info@domaine.com) vers des boîtes aux lettres réelles', 'Mappe les adresses IP externes sur des serveurs internes', 'Crée des réponses automatiques d\'absence'], answer: 1, explanation: 'Les alias virtuels réécrivent les adresses des destinataires, couramment utilisés pour la redirection.' },

  { id: 'lpic2-212-6', topicId: 13, question: 'Dans iptables, quelle option ajoute une règle tout au bas d\'une chaîne ?', options: ['-I', '-A', '-D', '-R'], answer: 1, explanation: '`-A` signifie Append (ajouter), tandis que `-I` insère une règle au début (ou à un numéro de ligne spécifié).' },
  { id: 'lpic2-212-7', topicId: 13, question: 'Quelle commande liste toutes les règles iptables de la table NAT ?', options: ['iptables -L', 'iptables -t nat -L', 'iptables -nL --table nat', 'iptables --list nat'], answer: 1, explanation: '`-t nat` spécifie la table cible, et `-L` liste les règles.' },
  { id: 'lpic2-212-8', topicId: 13, question: 'Quelle chaîne de filtrage dans iptables gère les paquets dont la destination finale est le serveur lui-même ?', options: ['FORWARD', 'OUTPUT', 'INPUT', 'PREROUTING'], answer: 2, explanation: 'La chaîne `INPUT` traite les paquets entrants adressés aux sockets locaux.' },
  { id: 'lpic2-212-9', topicId: 13, question: 'Dans `iptables`, que fait la cible `MASQUERADE` ?', options: ['Elle cache les données du paquet', 'Elle traduit dynamiquement l\'IP source des paquets sortants par l\'IP de l\'interface de sortie', 'Elle bloque les pirates connus', 'Elle crée un tunnel VPN'], answer: 1, explanation: 'Le Masquerading est un SNAT dynamique, largement utilisé sur les routeurs avec des IP publiques dynamiques.' },
  { id: 'lpic2-212-10', topicId: 13, question: 'Avec Nmap, que spécifie l\'option `-sS` ?', options: ['Scan UDP', 'Scan TCP SYN (furtif)', 'Scan TCP Connect', 'Scan FIN'], answer: 1, explanation: 'Le scan SYN effectue une poignée de main TCP semi-ouverte très efficace pour cartographier les ports.' },
  { id: 'lpic2-212-11', topicId: 13, question: 'Quel argument en ligne de commande demande à Nmap de tenter d\'identifier le système d\'exploitation de l\'hôte distant ?', options: ['-O', '-sV', '-A', 'Les deux (A et C)'], answer: 3, explanation: '`-O` active spécifiquement la détection du SE. `-A` (Agressif) active la détection du SE ainsi que le balayage des versions et des scripts.' },
  { id: 'lpic2-212-12', topicId: 13, question: 'Dans Fail2ban, quel fichier les administrateurs doivent-ils utiliser pour personnaliser les configurations de "prison" (jail) afin d\'empêcher les mises à jour de paquets de les écraser ?', options: ['jail.conf', 'fail2ban.conf', 'jail.local', 'iptables.local'], answer: 2, explanation: '`jail.local` l\'emporte sur `jail.conf`, servant de dépôt sûr pour les modifications locales.' },
  { id: 'lpic2-212-13', topicId: 13, question: 'Quelle variable dans Fail2ban définit la durée (en secondes) pendant laquelle une IP fautive reste bloquée ?', options: ['blocktime', 'findtime', 'maxretry', 'bantime'], answer: 3, explanation: '`bantime` définit combien de temps l\'injection DROP d\'iptables est laissée en place.' },
  { id: 'lpic2-212-14', topicId: 13, question: 'Quel est le framework noyau fondamental sur lequel repose iptables pour s\'accrocher à la pile réseau ?', options: ['BPF', 'Netfilter', 'TCP Wrapper', 'AppArmor'], answer: 1, explanation: 'Netfilter fournit les hooks dans le noyau Linux qui permettent à iptables/nftables d\'intercepter et de manipuler les paquets.' },
  { id: 'lpic2-212-15', topicId: 13, question: 'Quelle commande enregistre de manière permanente les règles iptables vers la sortie standard sur la plupart des distributions pour les scripts de sauvegarde ?', options: ['iptables-save', 'iptables-backup', 'iptables -S', 'service iptables save'], answer: 0, explanation: '`iptables-save` exporte les règles dans un format lisible par la machine (qui peut être restauré via `iptables-restore`).' },
  { id: 'lpic2-212-16', topicId: 13, question: 'Qu\'est-ce qu\'un test de vulnérabilité réseau (NVT) dans le contexte d\'OpenVAS/Greenbone ?', options: ['Un renifleur de paquets', 'Un script de plugin fournissant la logique pour détecter une vulnérabilité spécifique sur un hôte distant', 'Une technique de scan de ports', 'Une règle de détection d\'intrusion'], answer: 1, explanation: 'Les NVT sont essentiellement les scripts de signature exécutés par OpenVAS pour confirmer si une cible est vulnérable.' },
  { id: 'lpic2-212-17', topicId: 13, question: 'Quelle commande purge (supprime) toutes les règles de la table iptables actuellement sélectionnée ?', options: ['iptables -X', 'iptables -Z', 'iptables -F', 'iptables -R'], answer: 2, explanation: '`-F` (Flush) supprime instantanément toutes les règles de toutes les chaînes (ou d\'une chaîne spécifiée).' },
];
